function Screenshots() {
  return (
    <Section n="10" kicker="睇真啲 · 同一個地盤" title={<>一個 demo 地盤，由開工睇到完工</>}>
      <SameProjectPill />
      <div className="space-y-16 md:space-y-24">
        {SHOTS.map((s, i) => (
          <div key={s.n} className={'grid md:grid-cols-2 gap-10 md:gap-12 items-center ' + (i % 2 ? 'md:[&>div:first-child]:order-2' : '')}>
            <div className="flex justify-center md:justify-end"><ShotPhone img={s.img} /></div>
            <div className="max-w-md mx-auto md:mx-0">
              <DrawingNo n={s.n} icon={s.icon} />
              <h3 className="font-heading font-bold text-xl md:text-2xl text-site-900">{s.what}</h3>
              <p className="mt-3 text-sm text-site-600 leading-relaxed">{s.how}</p>
              <div className="mt-3 rounded-lg bg-safety-50 ring-1 ring-safety-100 px-3 py-2 text-sm font-medium text-safety-700">{s.why}</div>
            </div>
          </div>
        ))}
      </div>
      <ChipStrip items={['每日日誌','物料叫料','圖則 PDF','行事曆','聯絡人']} />
    </Section>
  )
}
// ShotPhone = PhoneMock bezel + orange CK / DC2026 油塘住宅 header + aspect-[9/19] <img object-cover object-top>
// SHOTS: [{n,icon,img,what,how,why}] in lifecycle order
// DrawingNo = mono {n} + h-px w-8 rule + {icon}
